function longestConsecutive(nums: number[]): number {
  const set = new Set(nums);
  let best = 0;
  for (const v of set) {
    if (!set.has(v - 1)) {
      let cur = v, len = 1;
      while (set.has(cur + 1)) { cur++; len++; }
      if (len > best) best = len;
    }
  }
  return best;
}
